import { cilSpeedometer, cilUser, cilSettings } from '@coreui/icons';
import CIcon from '@coreui/icons-react';

const navigation = [
  {
    component: 'CNavItem',
    name: 'Dashboard',
    to: '/dashboard',
    icon: <CIcon icon={cilSpeedometer} customClassName="nav-icon text-indigo" />,
  },
  {
    component: 'CNavItem',
    name: 'Users',
    to: '/users',
    icon: <CIcon icon={cilUser} customClassName="nav-icon text-green" />,
  },
  {
    component: 'CNavItem',
    name: 'Settings',
    to: '/settings',
    icon: <CIcon icon={cilSettings} customClassName="nav-icon text-gray" />,
  },
];

export default navigation;
